928	func (m *WorkerManager) List() ([]WorkerRecord, error) {
929		if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
930			return nil, err
931		}
932		entries, err := os.ReadDir(m.rootDir)
933		if err != nil {
934			return nil, err
935		}
936		var out []WorkerRecord
937		for _, entry := range entries {
938			if !entry.IsDir() {
939				continue
940			}
941			rec, err := m.readRecord(filepath.Join(m.rootDir, entry.Name()))
942			if err != nil {
943				continue
944			}
945			out = append(out, rec)
946		}
947	
948		// Merge in-memory state for active workers
949		m.mu.Lock()
950		for i := range out {
951			if handle, ok := m.workers[out[i].ID]; ok {
952				out[i] = handle.record
953			}
954		}
955		m.mu.Unlock()
956	
957		sort.Slice(out, func(i, j int) bool {
958			return out[i].StartedAt.After(out[j].StartedAt)
959		})
960	
961		// Compute PIDAlive for each record so operators can see liveness at a
962		// glance without running prune. This is a syscall per record; it's safe
963		// because List() is not on a hot path (workers are long-lived).
964		for i := range out {
965			if out[i].PID > 0 {
966				alive := isPIDAlive(out[i].PID)
967				out[i].PIDAlive = &alive
968			}
969		}
970	
971		return out, nil
972	}
