985	// Stop performs a graceful termination of the worker:
986	//  1. Mark state=stopping and persist so observers see the transition.
987	//  2. Emit bead.stopped event + release the bead claim (if one is held).
988	//  3. Send SIGTERM to the worker's process group; escalate to SIGKILL
989	//     after WatchdogKillGrace if the leader is still alive. Pure-goroutine
990	//     workers have no PID — ctx cancellation below is the only lever.
991	//  4. Cancel the worker's context so the loop and in-flight executor exit.
992	//  5. Mark state=stopped and persist. runWorker preserves this terminal
993	//     state when it writes its final record.
994	//
995	// Stop is idempotent: a second call is a no-op. It returns an error only
996	// when the worker is unknown to the manager (already exited / never existed).
997	// stopStaleDiskEntry handles the case where a worker's disk record shows
998	// state=running but no live goroutine exists (e.g. after a server restart).
999	// It releases any held bead claim and flips the on-disk state to "stopped".
1000	func (m *WorkerManager) stopStaleDiskEntry(id string) error {
1001		dir := filepath.Join(m.rootDir, id)
1002		rec, err := m.readRecord(dir)
1003		if err != nil {
1004			return fmt.Errorf("worker not running")
1005		}
1006		// Terminal state — nothing left to clean up.
1007		if rec.State != "running" && rec.State != "stopping" {
1008			return nil
1009		}
1010	
1011		now := time.Now().UTC()
1012		beadID := ""
1013		if rec.CurrentAttempt != nil {
1014			beadID = rec.CurrentAttempt.BeadID
1015		}
1016		if beadID == "" {
1017			beadID = rec.CurrentBead
1018		}
1019		projectRoot := rec.ProjectRoot
1020		if projectRoot == "" {
1021			projectRoot = m.projectRoot
1022		}
1023	
1024		if beadID != "" {
1025			store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
1026			body := fmt.Sprintf(
1027				"worker=%s pid=%d reason=stop-stale",
1028				id, rec.PID,
1029			)
1030			_ = store.AppendEvent(beadID, bead.BeadEvent{
1031				Kind:      "bead.stopped",
1032				Summary:   "stop (stale)",
1033				Body:      body,
