2450	// resolveRequestedProject matches a requested project_root string against
2451	// registered projects. It tries exact path match first, then name (basename)
2452	// match. Returns the canonical path on success, or "" if no match or ambiguous.
2453	func (s *Server) resolveRequestedProject(requested string) string {
2454		// Exact path match via the state's lookup method.
2455		if entry, ok := s.state.GetProjectByPath(requested); ok {
2456			return entry.Path
2457		}
2458		// Name (basename) match — only unambiguous if exactly one project has that name.
2459		projects := s.state.GetProjects()
2460		var matches []string
2461		for _, p := range projects {
2462			if p.Name == requested {
2463				matches = append(matches, p.Path)
2464			}
2465		}
2466		if len(matches) == 1 {
2467			return matches[0]
2468		}
2469		return ""
